// monster — Rust executor for polyglot orchestration GGs.
//
// Pipeline:
//   .ts source ─[gnosis-polyglot --mode orchestration]─▶ orchestration GG
//              ─[walk topology + eval AST nodes via tree-sitter]─▶ result
//
// No Node, no V8. Compile TS to GG, run it.

use std::cell::{OnceCell, RefCell};
use std::collections::{HashMap, HashSet};
use std::io::{self, BufRead, Read, Write};
use std::path::PathBuf;
use std::process::{self, Command, Stdio};
