/// Inline FxHash (the rustc hasher): multiply-xor, no SipHash rounds.
/// Used for interpreter-internal maps only — scope bindings, per-walk
/// loop state, AST memos, tree caches. These keys come from the program
/// text and GG node indexes, not from an attacker-controlled trust
/// boundary, so DoS-resistant hashing buys nothing here; callgrind
/// attributed ~15% of resident-walk instructions to SipHash before
/// this swap. Inlined (30 lines) rather than added as a dependency.
mod fx {
    use std::hash::{BuildHasherDefault, Hasher};

    pub type FxHashMap<K, V> = std::collections::HashMap<K, V, BuildHasherDefault<FxHasher>>;
    pub type FxHashSet<K> = std::collections::HashSet<K, BuildHasherDefault<FxHasher>>;

    const SEED: u64 = 0x51_7c_c1_b7_27_22_0a_95;

    #[derive(Default)]
    pub struct FxHasher {
        hash: u64,
    }

    impl FxHasher {
        #[inline]
        fn add(&mut self, word: u64) {
            self.hash = (self.hash.rotate_left(5) ^ word).wrapping_mul(SEED);
        }
    }

    impl Hasher for FxHasher {
        #[inline]
        fn write(&mut self, bytes: &[u8]) {
            for chunk in bytes.chunks(8) {
                let mut buf = [0u8; 8];
                buf[..chunk.len()].copy_from_slice(chunk);
                self.add(u64::from_le_bytes(buf));
            }
        }
        #[inline]
        fn write_u8(&mut self, n: u8) {
            self.add(n as u64);
        }
        #[inline]
        fn write_u32(&mut self, n: u32) {
            self.add(n as u64);
        }
        #[inline]
        fn write_u64(&mut self, n: u64) {
            self.add(n);
        }
        #[inline]
        fn write_usize(&mut self, n: usize) {
            self.add(n as u64);
        }
        #[inline]
        fn finish(&self) -> u64 {
            self.hash
        }
    }
}
