const LEGACY_DEADLINE_PULSE_HOPS: usize = 256;
/// Per-turn wall-clock floor for script-mode (`__module_main__`) runs. The CLI
/// default (5s) is tuned for one-shot topology probes; a real imperative turn
/// (the MCP bridge's `tools/list` is ~7s of legit fetch+parse+sanitize work)
/// blows past it. Floored here so the deadline guards only true runaway loops,
/// not heavy-but-finite turns. `--timeout-ms 0` disables; larger values win.
const SCRIPT_MODE_TURN_BUDGET_MS: u64 = 60_000;
static FOIL_PROBABILITY_ROUTE_CACHE_ENABLED: OnceLock<bool> = OnceLock::new();

thread_local! {
    static FOIL_PROBABILITY_ROUTE_CACHE: RefCell<HashMap<String, String>> =
        RefCell::new(HashMap::new());
}

thread_local! {
    /// The script path + interpreter-style args supplied via `--argv`, set
    /// once in `run()` before execution. Surfaced to programs as
    /// `process.argv` / `sys.argv` so redirected interpreter calls observe
    /// their arguments. Empty path means "not set" (fall back to the process
    /// args, preserving legacy behavior for direct `monster file.ts` runs).
    static SCRIPT_ARGV: RefCell<(String, Vec<String>)> =
        const { RefCell::new((String::new(), Vec::new())) };
}

thread_local! {
    /// The module's top-level `const`/`let`/`var` bindings, evaluated ONCE from
    /// the Entry preamble and shared across every function call. This is the JS
    /// module scope: a function reached via an inner call (`main()` → `load()`)
    /// must see module consts, not an opaque shim. `None` until first populated.
    static MODULE_SCOPE: RefCell<Option<Scope>> = const { RefCell::new(None) };
    /// Re-entrancy guard: while the preamble itself is being evaluated, a
    /// `const x = someFn()` line walks `someFn`, which must NOT try to populate
    /// the module scope again (infinite recursion).
    static MODULE_POPULATING: RefCell<bool> = const { RefCell::new(false) };
}

/// Populate the shared module scope once from this Entry's preamble (every
/// Entry carries the same lifted top-level bindings). Guarded against the
/// re-entrancy a self-referential preamble would cause.
fn ensure_module_scope(entry: &GgNode, ctx: &mut Ctx) {
    let already = MODULE_SCOPE.with(|ms| ms.borrow().is_some());
    let populating = MODULE_POPULATING.with(|p| *p.borrow());
    if already || populating {
        return;
    }
    let Some(preamble) = entry.runtime.module_preamble(&entry.properties) else {
        // No preamble (analysis mode / older GG): mark empty so we don't retry.
        MODULE_SCOPE.with(|ms| *ms.borrow_mut() = Some(Scope::new()));
        return;
    };
    MODULE_POPULATING.with(|p| *p.borrow_mut() = true);
    let debug_pre = std::env::var("GNEXEC_DEBUG_PREAMBLE").is_ok();
    // Publish the module scope INCREMENTALLY (start empty, not None) so that a
    // preamble initializer that calls a module-level function — e.g.
    // `const DEFAULT = resolveBrowserModel(ID)` or
    // `const X = Object.fromEntries(listModels().map(...))` — sees the bindings
    // evaluated by EARLIER preamble decls when that function seeds itself from
    // the module scope. Previously MODULE_SCOPE stayed None for the whole
    // population pass, so any such nested call resolved module consts to opaque
    // shims (the bug that broke aether's model registry: AETHER_MODEL_ALIASES /
    // AETHER_FRONTIER_MODELS came back as `{__module_shim__}` inside
    // resolveAetherModel, yielding a null model and a non-functional engine).
    MODULE_SCOPE.with(|ms| {
        if ms.borrow().is_none() {
            *ms.borrow_mut() = Some(Scope::new());
        }
    });
    // Two-pass fixpoint: a decl that throws on pass 1 (because a binding it
    // needs is defined LATER in preamble order) is retried on pass 2 once the
    // forward binding exists. Stop early when a pass makes no progress.
    let mut pending: Vec<&Value> = preamble.iter().collect();
    if debug_pre {
        eprintln!("[preamble] total decls = {}", pending.len());
    }
    let mut pass = 0;
    while !pending.is_empty() && pass < 4 {
        pass += 1;
        let prev_len = pending.len();
        let mut next_pending: Vec<&Value> = Vec::new();
        for decl in pending.into_iter() {
            let (Some(bind), Some(expr)) =
                (decl.get("bind").and_then(Value::as_str), decl.get("expr"))
            else {
                continue;
            };
            if debug_pre {
                eprintln!("[preamble:{pass}] EVAL-BEGIN {bind}");
            }
            // Seed a working scope from what's published so far so the
            // initializer can reference earlier module consts directly.
            let mut work = Scope::new();
            seed_from_module_scope(&mut work);
            match eval_ir(expr, &mut work, ctx) {
                Ok(v) => {
                    if debug_pre {
                        eprintln!(
                            "[preamble:{pass}] {bind} = {}",
                            &format!("{v:?}").chars().take(120).collect::<String>()
                        );
                    }
                    // Publish into the shared module scope immediately so the
                    // next decl (and any function it calls) can see it.
                    MODULE_SCOPE.with(|ms| {
                        if let Some(m) = &mut *ms.borrow_mut() {
                            m.set(bind, v);
                        }
                    });
                }
                Err(e) => {
                    if debug_pre {
                        eprintln!("[preamble:{pass}] {bind} ERR: {e}");
                    }
                    next_pending.push(decl);
                }
            }
        }
        // Stop if nothing resolved this pass (no forward-reference progress is
        // possible) or everything resolved.
        if next_pending.is_empty() || next_pending.len() == prev_len {
            break;
        }
        pending = next_pending;
    }
    MODULE_POPULATING.with(|p| *p.borrow_mut() = false);
}

/// Seed a fresh function scope with the shared module bindings (without
/// overwriting params/locals already present).
fn seed_from_module_scope(scope: &mut Scope) {
    MODULE_SCOPE.with(|ms| {
        if let Some(m) = &*ms.borrow() {
            for (k, v) in m.bindings.iter() {
                if !scope.bindings.contains_key(k) {
                    scope.bindings.insert(k.clone(), v.clone());
                }
            }
        }
    });
}

/// Record the script path and interpreter-style args for `process.argv` /
/// `sys.argv`. Called from `run()` right after CLI parse.
fn set_script_argv(script_path: &str, args: &[String]) {
    SCRIPT_ARGV.with(|cell| {
        *cell.borrow_mut() = (script_path.to_string(), args.to_vec());
    });
}

/// Node `process.argv`: `[execPath, scriptPath, ...args]`. When no script
/// path was recorded (legacy direct invocation), fall back to the real
/// process args so existing scripts keep observing something sensible.
fn script_process_argv() -> Vec<Value> {
    SCRIPT_ARGV.with(|cell| {
        let (path, args) = &*cell.borrow();
        if path.is_empty() {
            return std::env::args().map(Value::String).collect();
        }
        let mut out = Vec::with_capacity(args.len() + 2);
        out.push(Value::String("monster".to_string()));
        out.push(Value::String(path.clone()));
        out.extend(args.iter().cloned().map(Value::String));
        out
    })
}

/// Python `sys.argv`: `[scriptPath, ...args]`.
fn script_sys_argv() -> Vec<Value> {
    SCRIPT_ARGV.with(|cell| {
        let (path, args) = &*cell.borrow();
        if path.is_empty() {
            // argv[0] is the script name in CPython; fall back to "<stdin>"
            // shape only when nothing was recorded.
            return std::iter::once(Value::String(String::new()))
                .chain(args.iter().cloned().map(Value::String))
                .collect();
        }
        std::iter::once(Value::String(path.clone()))
            .chain(args.iter().cloned().map(Value::String))
            .collect()
    })
}

#[derive(Debug, ClapParser)]
#[command(
    name = "monster",
    about = "Run a source file by compiling to GG and walking the topology natively (no Node)."
)]
struct Cli {
    file: PathBuf,
    #[arg(long = "input-json", default_value = "{}")]
    input_json: String,
    #[arg(long = "export")]
    export_name: Option<String>,
    #[arg(long, default_value_t = false)]
    print_gg: bool,
    #[arg(long, default_value_t = false)]
    trace_timings: bool,
    #[arg(long, default_value_t = false)]
    print_fingerprint: bool,
    /// Keep Monster resident, read one JSON input value per stdin line, and
    /// write one JSON result envelope per stdout line. The source file and
    /// topology are extracted once before the loop, so this measures request
    /// execution instead of process startup.
    #[arg(long = "resident-jsonl", default_value_t = false)]
    resident_jsonl: bool,
    /// Keep Monster resident and speak Aeon Flow frames over stdio. Each input
    /// payload is a raw UTF-8 user id and each output payload is the raw fanout
    /// result. This is the bitwise hot lane for measuring JSONL overhead.
    #[arg(long = "resident-flow-stdio", default_value_t = false)]
    resident_flow_stdio: bool,
    /// Keep Monster resident and WALK the entry topology once per JSONL
    /// input line (each line is the request's input JSON; each output
    /// line is `{ok, index, result|error, elapsed_ns}`). Unlike
    /// `--resident-jsonl` (the foil-fanout hot lane), this mode runs the
    /// topology walker per request. The scan, indexes, and the FOIL
    /// session license are computed ONCE at load; on a certified license
    /// (structural, or opt-in via --foil-vacuum / GNEXEC_FOIL_VACUUM=1)
    /// the per-request wall-clock guard is dropped for the whole session
    /// (Lean: `session_vacuum_noop`, `stream_vacuum_noop`).
    #[arg(long = "resident-walk", default_value_t = false)]
    resident_walk: bool,
    /// Maximum recursion depth for `call_topology` / `invoke_callable`.
    /// Default 1024 keeps us well below the OS stack limit. Cap is 10000.
    #[arg(long = "max-call-depth", default_value_t = 1024)]
    max_call_depth: usize,
    /// Wall-clock budget in milliseconds. Default 5000 (5s). Set 0 to
    /// disable. The walker checks this at each topology hop and at every
    /// loop iteration; on overrun it bails with `GnexecError::Timeout`.
    /// This is what keeps wide-recon scans from hanging on pathological
    /// real-world functions (deep recursion, unguarded loops over null).
    #[arg(long = "timeout-ms", default_value_t = 5000)]
    timeout_ms: u64,
    /// Print the current Monster facet tree as JSON after applying any
    /// requested facet operation. Facets are shell tabs backed by the same
    /// fork/race/fold route index the evaluator uses; this is a scheduler
    /// surface, not a UI-only decoration.
    #[arg(long = "print-facets", default_value_t = false)]
    print_facets: bool,
    /// Print the BallisticVest-derived posture for the selected execution
    /// surface. This is observational only and writes to stderr so stdout
    /// remains the program/protocol output channel.
    #[arg(long = "print-posture", default_value_t = false)]
    print_posture: bool,
    /// Fork the active facet into two children and move into the left child.
    /// If the entry topology has a fork node with two targets, those children
    /// are anchored to the first cached fork pair; otherwise they stay at the
    /// active cursor as shell facets.
    #[arg(long = "facet-fork", default_value_t = false)]
    facet_fork: bool,
    /// Close every facet except the active one and its ancestor chain.
    #[arg(long = "facet-close-all-others", default_value_t = false)]
    facet_close_all_others: bool,
    /// Close all descendants of the active facet.
    #[arg(long = "facet-close-children", default_value_t = false)]
    facet_close_children: bool,
    /// Opt-in Ackermann-class admission gate. When enabled, runs
    /// `gnosis_polyglot::ackermann_admission::gate_call_depth` against a
    /// conservative `step_at` proxy BEFORE invoking the program. A
    /// `Reject` verdict exits cleanly with code 2 and a reason on stderr;
    /// an `Admit*` verdict proceeds with the legacy depth+time guards
    /// still in place (belt-and-suspenders). Off by default for byte-
    /// identical legacy behavior. Also enableable via env var
    /// `GNEXEC_ACKERMANN_ADMISSION=1`.
    #[arg(long = "ackermann-admission", default_value_t = true)]
    ackermann_admission: bool,
    /// FOIL vacuum opt-in. When the Ackermann admission gate returns a
    /// certified `AdmitPrimitiveRecursive` verdict, drop the wall-clock
    /// deadline guard for the run: `check_deadline` stops reading the
    /// clock on every topology hop, because the certificate makes the
    /// timeout vacuous on the calibration window (the descent is free —
    /// see `Gnosis/FoilVacuumAdmission.lean` in gnosis-math). The
    /// `max_call_depth` OS-stack backstop is a physical machine limit,
    /// not a growth-class guard, and stays in force inside the vacuum.
    /// The vacuum also engages WITHOUT this flag when the structural
    /// estimator certifies the program loop-free and cycle-free (the
    /// deadline provably cannot be load-bearing there); for programs
    /// with loops, certified degrees stay opt-in because the degree
    /// speaks to growth in input size, not to termination of an
    /// unguarded `while (true)`. Env: `GNEXEC_FOIL_VACUUM=1` opts in,
    /// `GNEXEC_FOIL_VACUUM=0` is the kill switch for both modes.
    #[arg(long = "foil-vacuum", default_value_t = false)]
    foil_vacuum: bool,
    /// Emit standalone C for the requested benchmark topology instead of
    /// executing it. Unsupported IR fails closed.
    #[arg(long = "emit-c", default_value_t = false)]
    emit_c: bool,
    /// Emit a standalone WebAssembly module (betti-wasm/1 manifest,
    /// scalar-v1/json-v1 gnosis ABI — see gnosis/src/wasm-execution-bridge.ts)
    /// for the requested topology instead of executing it. Raw module bytes
    /// go to stdout unless --emit-wasm-out is given. Unsupported IR fails
    /// closed, exactly like --emit-c.
    #[arg(long = "emit-wasm", default_value_t = false)]
    emit_wasm: bool,
    /// Write the emitted WASM module to this path; the betti-wasm/1 manifest
    /// lands beside it as `<path minus .wasm>.manifest.json`. Implies
    /// --emit-wasm.
    #[arg(long = "emit-wasm-out")]
    emit_wasm_out: Option<PathBuf>,
    /// Print the betti-wasm/1 manifest JSON to stdout. Implies --emit-wasm;
    /// combine with --emit-wasm-out to also write the module + manifest pair.
    #[arg(long = "emit-wasm-manifest", default_value_t = false)]
    emit_wasm_manifest: bool,
    /// Emit the Tier C interpreter-embed artifact trio
    /// (<artifactId>.{wasm,manifest.json,topology.json}) into this directory
    /// instead of executing. Packages the prebuilt gg-walker wasm (override
    /// via GG_WALKER_WASM_PATH); unsupported topologies fail closed.
    #[arg(long = "emit-gg-embed-out")]
    emit_gg_embed_out: Option<PathBuf>,
    /// Print the Tier C envelope material + admission verdict as JSON to
    /// stdout ({admitted, reasons, envelope}) WITHOUT needing the walker
    /// binary — the walker-free probe used by hosted compile services to
    /// decide whether a program can ride the interpreter-embed lane.
    #[arg(long = "emit-gg-envelope", default_value_t = false)]
    emit_gg_envelope: bool,
    /// Print the Tier-C (gg-walker interpreter-embed) admission report for
    /// the requested export as JSON to stdout — `{"admitted": bool,
    /// "reasons": [...]}` — and exit without executing. When the input file
    /// is itself a topology sidecar (`*.json`: a bare GgTopology or the
    /// program wrapper `{"topology": …, "helpers": {…}}`), the report is
    /// computed over the sidecar directly (no language front-end needed).
    /// This flag exposes the ONE Tier-C admission definition — the walker
    /// rlib's `validate_program` — that the TS edge runtime
    /// (open-source/x-gnosis/src/gg-admission.ts) mirrors and parity-tests.
    #[arg(long = "print-gg-admission", default_value_t = false)]
    print_gg_admission: bool,
    /// Legacy no-op compatibility flag for older scripts that gated C AOT
    /// behind an explicit instability acknowledgement.
    #[arg(long = "unstable-aot-c", default_value_t = false)]
    _unstable_aot_c: bool,
    /// Legacy explicit C AOT request. C AOT is now attempted by default for
    /// supported topologies; unsupported topologies continue through the normal
    /// Monster walker.
    #[arg(long = "aot-cached", default_value_t = true)]
    aot_cached: bool,
    /// Opt out of the default cached C AOT path. Also settable with
    /// `GNEXEC_AOT_C=0`, `GNEXEC_AOT_C=false`, or `GNEXEC_NO_AOT_C=1`.
    #[arg(long = "no-aot-c", alias = "no-aot-cached", default_value_t = false)]
    no_aot_c: bool,
    /// Enable EHLA (Entropy-Harvesting Latent Architecture) for latent
    /// execution of topologies. Harvests interpretation gaps to accelerate
    /// throughput while proofs are in-flight.
    #[arg(long = "ehla", default_value_t = true, overrides_with = "no_ehla")]
    ehla: bool,
    /// Disable EHLA and force rigid, blocking verification.
    #[arg(long = "no-ehla", overrides_with = "ehla")]
    no_ehla: bool,
    /// Maximum interpretation debt (unresolved proofs) allowed when EHLA
    /// is enabled before blocking for rigid verification.
    #[arg(long = "ehla-max-debt", default_value_t = 10)]
    ehla_max_debt: u32,
    /// Interpreter-style script arguments. Repeatable: `--argv a --argv b`.
    /// These are exposed to the running program as `process.argv`
    /// (`[execPath, scriptPath, ...argv]`, Node convention) and as `sys.argv`
    /// (`[scriptPath, ...argv]`, Python convention), so a moonshine shim can
    /// redirect `python script.py a b c` onto the sovereign runtime and have
    /// the script see its arguments exactly as the real interpreter would.
    #[arg(long = "argv")]
    argv: Vec<String>,
    /// Allow real outbound network I/O for `fetch(...)` in script mode
    /// (`monster script.mjs`). OFF by default: with the network disabled,
    /// `fetch` fails closed (`unsupported_shim`) rather than silently
    /// returning a lying stub. When enabled, `fetch` performs a real
    /// (synchronous, rustls-TLS) HTTP request via `ureq`. Also settable with
    /// `GNEXEC_ALLOW_NET=1`. This is the Stage-4 gate for the MCP stdio
    /// bridge, which forwards JSON-RPC frames to a remote `/mcp` endpoint.
    #[arg(long = "allow-net", default_value_t = false)]
    allow_net: bool,
}

