    #[test]
    fn facet_tree_close_operations_are_descendant_scoped() {
        let topology = Topology {
            nodes: vec![test_node("entry", &["Entry"])],
            edges: Vec::new(),
        };
        let by_id: HashMap<&str, usize> = topology
            .nodes
            .iter()
            .enumerate()
            .map(|(i, node)| (node.id.as_str(), i))
            .collect();
        let edge_index = TopologyEdgeIndex::from_topology(&topology, &by_id);
        let mut facets = FacetTree::new(0);

        facets.fork_active(&edge_index);
        facets.fork_active(&edge_index);
        facets.active = 1;
        facets.close_children();

        assert!(facets.nodes[facets.active].open);
        assert!(!facets.nodes[3].open);
        assert!(!facets.nodes[4].open);

        facets.close_all_others();

        assert!(facets.nodes[0].open);
        assert!(facets.nodes[facets.active].open);
        assert_eq!(facets.open_count(), 2);
    }

